    inout  wire   [`DQ_BITS-1:0]  dq;
	  inout  wire   [8*`DQ_BITS-1:0] dq_all;
	  inout  wire   [`DQS_BITS-1:0] dqs;
	  inout  wire   [`DQS_BITS-1:0] dqs_n;

